content.text:
In JavaScript, a class with a constructor is defined as follows:
```javascript
class Name {
  constructor(param1, param2) {
    this.property1 = param1;
    this.property2 = param2;
  }
}
```
- `class`: Keyword to define a class.
- `constructor`: Special method called when an object is created.
- `this`: Refers to the properties of the new object.
- Objects are created using the `new` keyword: `const object = new Name(value1, value2);`

content.code:
// Defining a class and constructor
class Car {
  constructor(brand, model) {
    this.brand = brand;
    this.model = model;
  }
}

// Creating an object
const myCar = new Car('Toyota', 'Corolla');
console.log(myCar.brand); // Toyota
console.log(myCar.model); // Corolla

// Constructor and method definition
class Person {
  constructor(name, age) {
    this.name = name;
    this.age = age;
  }
  introduce() {
    return 'Hi, I am ' + this.name + ' and I am ' + this.age + ' years old.';
  }
}

// Creating an object and calling a method
const person = new Person('Aysu', 22);
console.log(person.introduce()); // Hi, I am Aysu and I am 22 years old.

// Error-prone example
class Student {
  // Error: No constructor defined
  name = 'Ali';
  showName() {
    return this.name;
  }
}

// Correct approach
class StudentCorrect {
  constructor(name) {
    this.name = name;
  }
  showName() {
    return this.name;
  }
}

const student = new StudentCorrect('Ali');
console.log(student.showName()); // Ali

// Error: Accessing non-existent property
console.log(student.age); // undefined

// Object literal
const personObj = {
  name: 'Veli',
  introduce: function() {
    return 'Hello, ' + this.name;
  }
};

// Same functionality with a class
class PersonClass {
  constructor(name) {
    this.name = name;
  }
  introduce() {
    return 'Hello, ' + this.name;
  }
}

console.log(personObj.introduce()); // Hello, Veli
console.log(new PersonClass('Veli').introduce()); // Hello, Veli

