content.text:
В JavaScript класс с конструктором определяется следующим образом:
```javascript
class Name {
  constructor(param1, param2) {
    this.property1 = param1;
    this.property2 = param2;
  }
}
```
- `class`: Ключевое слово для определения класса.
- `constructor`: Специальный метод, вызываемый при создании объекта.
- `this`: Ссылается на свойства нового объекта.
- Объекты создаются с помощью ключевого слова `new`: `const object = new Name(value1, value2);`

content.code:
// Определение класса и конструктора
class Car {
  constructor(brand, model) {
    this.brand = brand;
    this.model = model;
  }
}

// Создание объекта
const myCar = new Car('Toyota', 'Corolla');
console.log(myCar.brand); // Toyota
console.log(myCar.model); // Corolla

// Определение конструктора и метода
class Person {
  constructor(name, age) {
    this.name = name;
    this.age = age;
  }
  introduce() {
    return 'Привет, я ' + this.name + ', мне ' + this.age + ' лет.';
  }
}

// Создание объекта и вызов метода
const person = new Person('Айсу', 22);
console.log(person.introduce()); // Привет, я Айсу, мне 22 лет.

// Пример с ошибкой
class Student {
  // Ошибка: Конструктор не определен
  name = 'Али';
  showName() {
    return this.name;
  }
}

// Правильный подход
class StudentCorrect {
  constructor(name) {
    this.name = name;
  }
  showName() {
    return this.name;
  }
}

const student = new StudentCorrect('Али');
console.log(student.showName()); // Али

// Ошибка: Доступ к несуществующему свойству
console.log(student.age); // undefined

// Объектный литерал
const personObj = {
  name: 'Вали',
  introduce: function() {
    return 'Привет, ' + this.name;
  }
};

// Та же функциональность с классом
class PersonClass {
  constructor(name) {
    this.name = name;
  }
  introduce() {
    return 'Привет, ' + this.name;
  }
}

console.log(personObj.introduce()); // Привет, Вали
console.log(new PersonClass('Вали').introduce()); // Привет, Вали

